def get_sum(a: int, b: int) -> int:
    # In Python integers are arbitrary-precision; mask to 32-bit two's complement
    MASK = 0xFFFFFFFF
    MAX = 0x7FFFFFFF

    while b & MASK:
        carry = (a & b) << 1
        a = a ^ b
        b = carry

    # If the result fits in a signed 32-bit integer, return it directly;
    # otherwise convert from two's complement representation
    return a if a <= MAX else ~(a ^ MASK)
